#pragma comment(linker, "/stack:200000000")
#include <bits/stdc++.h>
#define rep(i, n) for(int i = 0; i < n; i++)
#define PI pair<int, int>
#define all(v) v.begin(), v.end()
#define ll long long

template <class T, class U> inline bool chmin(T &a, U b) {
    if(a > b) {
        a = b;
        return true;
    }
    return false;
}
template <class T, class U> inline bool chmax(T &a, U b) {
    if(a < b) {
        a = b;
        return true;
    }
    return false;
}
using namespace std;

struct UnionFind {
    int N;
    vector<int> par, siz;
    int find(int x) { return (par[x] == x ? x : par[x] = find(par[x])); }
    void merge(int x, int y) {
        x = find(x), y = find(y);
        if(x == y) return;
        if(siz[x] > siz[y]) swap(x, y);
        par[x] = y;
        siz[y] += siz[x];
    }
    UnionFind(int N) : N(N), siz(N, 1), par(N) { iota(par.begin(), par.end(), 0); }
};

// 方向を表す
int dx[] = {-1, 0, 1, 0}, dy[] = {0, 1, 0, -1};

// 操作
struct Act {
    int type, x, y;
};

struct Game {
    vector<vector<bool>> C;
    vector<vector<bool>> wall_hrz, wall_vert;
    vector<int> X, Y, wall_used, score;
    bool is_finished = false;

    int MAX_WALL = 10;
    int turn = 0;
    vector<Act> acts;

    // 連結性が保たれているかの判定
    bool isConnected() {
        UnionFind uf(81);
        rep(i, 9) rep(j, 9) {
            if(i < 8 && !wall_hrz[i][j]) uf.merge(i * 9 + j, (i + 1) * 9 + j);
            if(j < 8 && !wall_vert[i][j]) uf.merge(i * 9 + j, i * 9 + j + 1);
        }
        return uf.siz[uf.find(0)] == 81;
    }

    // 操作が適正であるかの判定
    bool isOK(Act act) {
        if(act.type == 0) {
            if(act.x == 0) // 上
                return X[turn] && !wall_hrz[X[turn] - 1][Y[turn]];
            else if(act.x == 1) // 右
                return Y[turn] != 8 && !wall_vert[X[turn]][Y[turn]];
            else if(act.x == 2) // 下
                return X[turn] != 8 && !wall_hrz[X[turn]][Y[turn]];
            else if(act.x == 3) // 左
                return Y[turn] && !wall_vert[X[turn]][Y[turn] - 1];
            else
                return false;
        } else if(act.type == 1) {
            if(act.x < 0 || act.x > 7 || act.y < 0 || act.y > 7) return false;
            if(wall_used[turn] == MAX_WALL) return false;            // 11 回目に置こうとしたらアウト
            if(wall_hrz[act.x][act.y] || wall_hrz[act.x][act.y + 1]) // 既に置かれていたらアウト
                return false;
            wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = true;
            bool res = isConnected(); // 連結性チェック
            wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = false;
            return res;
        } else if(act.type == 2) {
            if(act.x < 0 || act.x > 7 || act.y < 0 || act.y > 7) return false;
            if(wall_used[turn] == MAX_WALL) return false;
            if(wall_vert[act.x][act.y] || wall_vert[act.x + 1][act.y]) return false;
            wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = true;
            bool res = isConnected();
            wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = false;
            return res;
        } else
            return false;
    }

    // 操作の候補
    vector<Act> candidateActs() {
        vector<Act> res;
        rep(i, 4) {
            if(isOK(Act{0, i, 0})) res.push_back(Act{0, i, 0}); // 隣接マスへ移動
        }
        rep(i, 9) rep(j, 9) {
            if(isOK(Act{1, i, j})) res.push_back(Act{1, i, j}); // 水平方向の壁
            if(isOK(Act{2, i, j})) res.push_back(Act{2, i, j}); // 垂直方向の壁
        }
        return res;
    }

    // 操作を実行する
    bool applyAct(Act act, bool check = true) {
        if(check && !isOK(act)) return false;
        if(act.type == 0) { // 隣接マスへ移動
            X[turn] += dx[act.x];
            Y[turn] += dy[act.x];
            if(C[X[turn]][Y[turn]]) {
                score[turn]++;
                C[X[turn]][Y[turn]] = false;
            }
        } else if(act.type == 1) { // 水平方向の壁
            wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = true;
            wall_used[turn]++;
        } else { // 垂直方向の壁
            wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = true;
            wall_used[turn]++;
        }
        // ゲームが終了しているかの判定
        bool flag = false;
        rep(i, 9) rep(j, 9) {
            if(C[i][j]) flag = true;
        }
        if(!flag) is_finished = true;
        acts.push_back(act);

        // 交代
        turn ^= 1;
        return true;
    }

    // スコアや盤面を出力する（デバッグ用）
    void printBoard() {
        cerr << "Score: " << score[0] << " " << score[1] << "\n"
             << "Wall counter: " << wall_used[0] << " " << wall_used[1] << endl
             << endl;
        rep(i, 9) {
            rep(j, 9) {
                if(i == X[0] && j == Y[0] && i == X[1] && j == Y[1])
                    cerr << " AB";
                else if(i == X[0] && j == Y[0])
                    cerr << " A ";
                else if(i == X[1] && j == Y[1])
                    cerr << " B ";
                else {
                    if(C[i][j])
                        cerr << " # ";
                    else
                        cerr << " . ";
                }
                if(j < 8) cerr << (wall_vert[i][j] ? " | " : "   ");
            }
            cerr << endl;
            if(i != 8) {
                rep(j, 9) {
                    if(j) cerr << "   ";
                    cerr << (wall_hrz[i][j] ? "---" : "   ");
                }
            }
            cerr << endl;
        }
        cerr << endl;
    }
    Game() : C(9, vector<bool>(9)), wall_hrz(9, vector<bool>(9)), wall_vert(9, vector<bool>(9)), X(2), Y(2), wall_used(2), score(2) {
        wall_used[0] = wall_used[1] = 0;
        score[0] = score[1] = 0;
        X[0] = 8, X[1] = 0, Y[0] = Y[1] = 4;
    }
    // 自分視点
    double evaluate() {
        const double A = 0.5, B = 1;
        vector dist(9, vector(9, vector<int>(2, 1000)));
        rep(t, 2) {
            dist[X[t]][Y[t]][t] = 0;
            queue<PI> q;
            q.emplace(X[t], Y[t]);
            while(not q.empty()) {
                int i, j;
                tie(i, j) = q.front();
                q.pop();
                rep(d, 4) {
                    int ni = i + dx[d];
                    int nj = j + dy[d];
                    if(ni < 0 or ni >= 9 or nj < 0 or nj >= 9) continue;
                    if(d == 0 and wall_hrz[ni][nj]) continue;
                    if(d == 1 and wall_vert[i][j]) continue;
                    if(d == 2 and wall_hrz[i][j]) continue;
                    if(d == 3 and wall_vert[ni][nj]) continue;
                    if(chmin(dist[ni][nj][t], dist[i][j][t] + 1)) q.emplace(ni, nj);
                }
            }
        }
        vector<double> sc(2);
        rep(t, 2) {
            sc[t] += B * score[t];
            rep(i, 9) rep(j, 9) {
                assert(dist[i][j][t] != 1000);
                sc[t] += exp(-A * dist[i][j][t]);
            }
        }
        if(turn == 0)
            return sc[0] - sc[1];
        else
            return sc[1] - sc[0];
    }
};

// 処理に掛かっている合計時間
double tim_sum;

struct Timer {
  private:
    chrono::high_resolution_clock::time_point start, end;

  public:
    Timer() { set(); }
    void set() { start = chrono::high_resolution_clock::now(); }
    int time() {
        end = chrono::high_resolution_clock::now();
        return chrono::duration_cast<chrono::milliseconds>(end - start).count();
    }
    bool before(double T) { return time() < (int)(T * 1000); }
    void print() { cerr << "elapsed time: " << (double)time() / 1000 << " sec" << endl; }
};

constexpr double time_per_turn = 0.7;
constexpr int beam_width = 200, beam_max = 200 * (64 * 2 + 4);
// 自分のターンになったら呼ばれるので、操作を選ぶ。先手なら game.turn=0,
// 後手なら game.turn=1 の状態で呼ばれる
Act choose(Game game) {
    // 時間計測用
    Timer timer;

    int beam_turn = game.turn;
    struct Beam_type {
        Game game;
        Act firstAct;
        double val;
        constexpr bool operator<(const Beam_type &rhs) const { return val > rhs.val; }
    };

    struct Beam {
        array<Beam_type, beam_max> v;
        int s = 0;
        void push(Beam_type &b) {
            b.val = b.game.evaluate();
            v[s++] = b;
        }
        void add(Beam_type &b) {
            auto cand = b.game.candidateActs();
            for(auto &&a : cand) {
                auto nb = b;
                nb.game.applyAct(a);
                push(nb);
            }
        }
    } beam;

    vector<Act> acts = game.candidateActs();
    for(auto &&a : acts) {
        Game new_game = game;
        new_game.applyAct(a);
        Beam_type b{new_game, a, 0.0};
        beam.push(b);
    }

    int iter = 0;
    while(timer.before(time_per_turn)) {
        iter++;
        Beam nxt_beam;
        rep(i, beam.s) {
            auto &&b = beam.v[i];
            nxt_beam.add(b);
        }
        // cerr << iter << endl;
        swap(beam, nxt_beam);
        if(beam.s > beam_width) {
            nth_element(beam.v.begin(), beam.v.begin() + beam_width, beam.v.begin() + beam.s);
            beam.s = beam_width;
        }
    }

    cerr << iter << endl;

    auto best_act = min_element(begin(beam.v), begin(beam.v) + beam.s)->firstAct;

    // 時間計測用
    tim_sum += timer.time() * 0.001;
    return best_act;
}

int main() {
    string s;
    cin >> s;
    Game game;
    rep(i, 9) {
        rep(j, 9) {
            char c;
            cin >> c;
            if(c == '#')
                game.C[i][j] = true;
            else
                game.C[i][j] = false;
        }
    }
    int turn = 0, myturn = (s == "First" ? 0 : 1);
    while(1) {
        if(turn == myturn) {
            Act act = choose(game);
            game.applyAct(act);
            if(!act.type) {
                cout << act.type << " " << act.x << endl;
            } else {
                cout << act.type << " " << act.x << " " << act.y << endl;
            }
        } else {
            int t;
            cin >> t;
            if(!t) {
                int x;
                cin >> x;
                game.applyAct(Act{0, x, 0});
            } else if(t <= 2) {
                int x, y;
                cin >> x >> y;
                game.applyAct(Act{t, x, y});
            } else {
                return 0;
            }
        }
        // デバッグ用
        // game.printBoard();
        turn ^= 1;
    }
}
